import React from 'react';

const SiteCard = ({ site, onEdit, onDelete, onCheck, checking }) => {
  const statusMap = {
    online: { cls: 'badge-online', label: 'En ligne', icon: '🟢' },
    offline: { cls: 'badge-offline', label: 'Hors ligne', icon: '🔴' },
    unknown: { cls: 'badge-unknown', label: 'Inconnu', icon: '🟡' },
  };

  const status = statusMap[site.status] || statusMap.unknown;

  const formatDate = (date) => {
    if (!date) return 'Jamais';
    return new Date(date).toLocaleString('fr-FR', {
      month: 'short', day: 'numeric',
      hour: '2-digit', minute: '2-digit',
    });
  };

  return (
    <div className="site-card">
      <div className="site-favicon">🌐</div>
      <div className="site-info">
        <div className="site-name">{site.name || site.domain}</div>
        <div className="site-domain">{site.domain}</div>
        <div style={{ marginTop: '4px', fontSize: '11px', color: 'var(--text-muted)' }}>
          <i className="bi bi-clock me-1"></i>
          Vérifié : {formatDate(site.last_checked)}
        </div>
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexShrink: 0, flexWrap: 'wrap', justifyContent: 'flex-end' }}>
        <span className={`badge-status ${status.cls}`}>
          <span className="pulse"></span>
          {status.label}
        </span>

        {/* Bouton refresh individuel */}
        <button
          className="btn-ghost"
          onClick={() => onCheck(site)}
          disabled={checking}
          title="Vérifier maintenant"
          style={{ padding: '7px 10px' }}
        >
          {checking ? (
            <span className="hm-spinner" style={{ width: '14px', height: '14px', borderWidth: '2px' }}></span>
          ) : (
            <i className="bi bi-arrow-clockwise"></i>
          )}
        </button>

        <button
          className="btn-ghost"
          onClick={() => onEdit(site)}
          title="Modifier"
          style={{ padding: '7px 10px' }}
        >
          <i className="bi bi-pencil"></i>
        </button>

        <button
          className="btn-danger-hm"
          onClick={() => onDelete(site)}
          title="Supprimer"
        >
          <i className="bi bi-trash"></i>
        </button>
      </div>
    </div>
  );
};

export default SiteCard;
